mapper.select:
SELECT id,user_id,activity_id,favorite_time
FROM activity_favorite WHERE
user_id = #{userId}

    AND activity_id = #{activityId}

ORDER BY
favorite_time DESC

SELECT ap.id, ap.plan_name, ap.min_age, ap.max_age, ap.activity_category, ap.season, ap.duration, ap.scene, ap.status, (SELECT COUNT(*) FROM activity_step s WHERE s.activity_plan_id = ap.id) AS step_count FROM activity_favorite f INNER JOIN activity_plan ap ON f.activity_id = ap.id WHERE f.user_id = #{userId}
AND f.activity_id = #{activityId}
ORDER BY f.favorite_time DESC

SELECT id, user_id, activity_id, favorite_time
FROM activity_favorite
WHERE user_id = #{userId} AND activity_id = #{activityId}

select f.id as favoriteId, f.user_id, f.activity_id,f.favorite_time, ap.plan_name, ap.min_age, ap.max_age, ap.activity_category, ap.season, ap.duration, ap.scene, ap.status, (select count(*) from activity_step s where s.activity_plan_id = ap.id) as step_count from activity_favorite f inner join activity_plan ap on f.activity_id = ap.id
and f.user_id = #{userId}
and f.activity_id = #{activityId}
order by f.favorite_time desc
